const ENT_COLORS = ['#6366f1','#10b981','#f59e0b','#ef4444','#8b5cf6','#06b6d4','#f97316','#84cc16','#ec4899','#14b8a6'];
const _UNUSED_LOGO = 'data:image/png;base64,';
const CHART_COLORS = ENT_COLORS;

function truncateText(t, n) { return t&&t.length>n?t.slice(0,n)+'…':t; }

export function ResponsiveContainer({ children, width="100%", height="100%" }) {
  const ref = useRef(null);
  const [dim, setDim] = useState({ width:0, height:0 });
  useEffect(() => {
    if (!ref.current) return;
    const ro = new ResizeObserver(entries => {
      const { width: w, height: h } = entries[0].contentRect;
      setDim({ width:w, height:h||300 });
    });
    ro.observe(ref.current);
    return () => ro.disconnect();
  }, []);
  return (
    <div ref={ref} style={{ width, height, position:'relative', overflow:'hidden' }}>
      {dim.width > 0 && React.Children.map(children, c =>
        React.isValidElement(c) ? React.cloneElement(c, { containerWidth:dim.width, containerHeight:dim.height }) : c
      )}
    </div>
  );
}

export const Bar=()=>null; export const Line=()=>null; export const XAxis=()=>null;
export const YAxis=()=>null; export const CartesianGrid=()=>null; export const Tooltip=()=>null;
export const Legend=()=>null; export const Cell=()=>null; export const LabelList=()=>null;
export const Pie=()=>null;
export function BarChart(p){return<CartesianChartE {...p}/>;}
export function LineChart(p){return<CartesianChartE {...p}/>;}
export function ComposedChart(p){return<CartesianChartE {...p}/>;}

function CartesianChartE({data=[],layout="horizontal",containerWidth=400,containerHeight=300,margin={top:15,right:15,left:15,bottom:15},children}){
  const [hov,setHov]=useState(null);
  const [mpos,setMpos]=useState({x:0,y:0});
  const ch=React.Children.toArray(children);
  const grid=ch.find(c=>c.type===CartesianGrid);
  const xax=ch.find(c=>c.type===XAxis);
  const yaxs=ch.filter(c=>c.type===YAxis);
  const tip=ch.find(c=>c.type===Tooltip);
  const leg=ch.find(c=>c.type===Legend);
  const series=ch.filter(c=>c.type===Bar||c.type===Line).map(c=>({
    type:c.type===Bar?'bar':'line',dataKey:c.props.dataKey,name:c.props.name||c.props.dataKey,
    fill:c.props.fill,stroke:c.props.stroke,yAxisId:c.props.yAxisId||'left',props:c.props
  }));
  if(!data||!data.length||!series.length)return(
    <svg width={containerWidth} height={containerHeight}>
      <text x={containerWidth/2} y={containerHeight/2} textAnchor="middle" fill="#94a3b8" fontSize={11}>Sem dados</text>
    </svg>
  );
  const xKey=xax?.props?.dataKey||'name';
  const lPad=layout==="vertical"?120:50;
  const bPad=xax?.props?.angle?70:50;
  const pad={top:margin.top||15,right:margin.right||15,left:(margin.left||0)+lPad,bottom:(margin.bottom||0)+bPad};
  const cW=Math.max(50,containerWidth-pad.left-pad.right);
  const cH=Math.max(50,containerHeight-pad.top-pad.bottom);
  const getRange=yid=>{
    const ks=series.filter(s=>s.yAxisId===yid).map(s=>s.dataKey);
    if(!ks.length)return{min:0,max:100};
    let vals=[];
    data.forEach(item=>ks.forEach(k=>{if(typeof k==='function')vals.push(parseFloat(k(item))||0);else if(item[k]!==undefined)vals.push(parseFloat(item[k])||0);}));
    const mx=Math.max(...vals,10);
    const nice=v=>{if(!v)return 10;const l=Math.floor(Math.log10(v));const p=Math.pow(10,l);const r=v/p;return([1,2,5,10].find(t=>t>=r)||10)*p;};
    return{min:0,max:nice(mx)};
  };
  const lr=getRange('left');const rr=getRange('right');
  const gY=(v,yid='left')=>{const rng=yid==='left'?lr:rr;return pad.top+cH-(v/rng.max)*cH;};
  const gX=v=>pad.left+(v/lr.max)*cW;
  const xSt=cW/data.length;
  const gCC=i=>pad.left+(i+0.5)*xSt;
  const gCX=i=>pad.left+i*xSt;
  const ySt=cH/data.length;
  const gCCY=i=>pad.top+(i+0.5)*ySt;
  const gCY=i=>pad.top+i*ySt;
  const tks=[0,.25,.5,.75,1];
  const fmt=v=>{if(!v&&v!==0)return'';const n=parseFloat(v);if(Math.abs(n)>=1e6)return(n/1e6).toFixed(1)+'M';if(Math.abs(n)>=1e3)return(n/1e3).toFixed(0)+'K';return n.toFixed(0);};
  const getTip=i=>{if(i===null||!data[i])return[];return series.map(s=>{const v=typeof s.dataKey==='function'?s.dataKey(data[i]):data[i][s.dataKey];return{name:s.name,value:v,color:s.fill||s.stroke||ENT_COLORS[0],payload:data[i]};});};
  const onMov=e=>{
    const r=e.currentTarget.getBoundingClientRect();const x=e.clientX-r.left;const y=e.clientY-r.top;
    setMpos({x,y});
    if(layout==="horizontal"){const ix=x-pad.left;if(ix>=0&&ix<=cW){const id=Math.floor(ix/xSt);setHov(id>=0&&id<data.length?id:null);}else setHov(null);}
    else{const iy=y-pad.top;if(iy>=0&&iy<=cH){const id=Math.floor(iy/ySt);setHov(id>=0&&id<data.length?id:null);}else setHov(null);}
  };
  return(
    <div style={{position:'relative',width:'100%',height:'100%'}} onMouseMove={onMov} onMouseLeave={()=>setHov(null)}>
      <svg width={containerWidth} height={containerHeight} className="overflow-visible select-none">
        {hov!==null&&layout==="horizontal"&&<rect x={gCX(hov)} y={pad.top} width={xSt} height={cH} fill="rgba(99,102,241,0.04)"/>}
        {hov!==null&&layout==="vertical"&&<rect x={pad.left} y={gCY(hov)} width={cW} height={ySt} fill="rgba(99,102,241,0.04)"/>}
        {grid&&tks.map((t,i)=>{
          if(layout==="horizontal"){const y=pad.top+t*cH;return<line key={i} x1={pad.left} y1={y} x2={pad.left+cW} y2={y} stroke={grid.props.stroke||"#e2e8f0"} strokeDasharray={grid.props.strokeDasharray||"3 3"}/>;}
          else{const x=pad.left+t*cW;return<line key={i} x1={x} y1={pad.top} x2={x} y2={pad.top+cH} stroke={grid.props.stroke||"#e2e8f0"} strokeDasharray={grid.props.strokeDasharray||"3 3"}/>;}
        })}
        {xax&&layout==="horizontal"&&data.map((item,i)=>{
          const lb=item[xKey];const cx=gCC(i);const cy=pad.top+cH+18;
          const f=xax.props.tickFormatter;const dl=f?f(lb):lb;
          if(xax.props.angle)return<text key={i} x={cx} y={cy} fontSize={xax.props.tick?.fontSize||9} fontWeight="600" fill={xax.props.tick?.fill||"#64748b"} textAnchor="end" transform={`rotate(${xax.props.angle},${cx},${cy})`}>{dl}</text>;
          return<text key={i} x={cx} y={cy} fontSize={10} fontWeight="600" fill="#64748b" textAnchor="middle">{dl}</text>;
        })}
        {layout==="vertical"&&tks.map((t,i)=>{const v=t*lr.max;const cx=pad.left+t*cW;const cy=pad.top+cH+18;return<text key={i} x={cx} y={cy} fontSize={10} fontWeight="600" fill="#64748b" textAnchor="middle">{fmt(v)}</text>;})}
        {yaxs.find(y=>y.props.yAxisId!=='right')&&layout==="horizontal"&&tks.map((t,i)=>{const v=(1-t)*lr.max;const x=pad.left-12;const y=pad.top+t*cH+4;const f=yaxs.find(y=>y.props.yAxisId!=='right').props.tickFormatter;return<text key={i} x={x} y={y} fontSize={10} fontWeight="600" fill="#64748b" textAnchor="end">{f?f(v):fmt(v)}</text>;})}
        {yaxs.find(y=>y.props.yAxisId==='right')&&layout==="horizontal"&&tks.map((t,i)=>{const v=(1-t)*rr.max;const x=pad.left+cW+12;const y=pad.top+t*cH+4;const f=yaxs.find(y=>y.props.yAxisId==='right').props.tickFormatter;return<text key={i} x={x} y={y} fontSize={10} fontWeight="600" fill="#64748b" textAnchor="start">{f?f(v):`${v}%`}</text>;})}
        {layout==="vertical"&&data.map((item,i)=>{const lb=item[xKey];const x=pad.left-12;const y=gCCY(i)+4;return<text key={i} x={x} y={y} fontSize={10} fontWeight="600" fill="#475569" textAnchor="end">{truncateText(String(lb),16)}</text>;})}
        {layout==="horizontal"?(
          <>
            {series.filter(s=>s.type==='bar').map((s,si,arr)=>{
              const tb=arr.length;const bGW=xSt*0.6;const bW=bGW/tb;
              return data.map((item,i)=>{
                const v=parseFloat(item[s.dataKey])||0;if(!v)return null;
                const cx=gCC(i);const sx=cx-bGW/2;const x=sx+si*bW+bW*0.06;const w=bW*0.88;
                const y=gY(v,s.yAxisId);const h=Math.max(2,pad.top+cH-y);
                let fill=s.fill||ENT_COLORS[si%ENT_COLORS.length];
                if(s.props.children){const cells=React.Children.toArray(s.props.children).filter(c=>c.type===Cell);if(cells[i])fill=cells[i].props.fill;}
                return<g key={`${si}-${i}`}><rect x={x} y={y} width={w} height={h} rx={3} fill={fill} opacity={hov!==null&&hov!==i?0.5:1} style={{transition:'opacity 0.15s'}}/>{React.Children.toArray(s.props.children).find(c=>c.type===LabelList)&&<text x={x+w/2} y={y-6} fill="#64748b" fontSize={9} fontWeight="700" textAnchor="middle">{fmt(v)}</text>}</g>;
              });
            })}
            {series.filter(s=>s.type==='line').map((s,si)=>{
              const pts=data.map((item,i)=>{const v=parseFloat(item[s.dataKey])||0;return{x:gCC(i),y:gY(v,s.yAxisId),v};});
              const d=pts.map((p,i)=>`${i===0?'M':'L'} ${p.x} ${p.y}`).join(' ');
              return<g key={`l-${si}`}><path d={d} fill="none" stroke={s.stroke||ENT_COLORS[si]} strokeWidth={s.props.strokeWidth||2.5} strokeLinecap="round" strokeLinejoin="round"/>{pts.map((p,i)=><circle key={i} cx={p.x} cy={p.y} r={4} fill={s.stroke||ENT_COLORS[si]} stroke="#fff" strokeWidth={2}/>)}</g>;
            })}
          </>
        ):(
          series.filter(s=>s.type==='bar').map((s,si,arr)=>{
            const tb=arr.length;const bGH=ySt*0.6;const bH=bGH/tb;
            return data.map((item,i)=>{
              const v=parseFloat(item[s.dataKey])||0;if(!v)return null;
              const cy=gCCY(i);const sy=cy-bGH/2;const y=sy+si*bH+bH*0.06;const h=bH*0.88;
              const x=pad.left;const w=Math.max(2,gX(v)-pad.left);
              let fill=s.fill||ENT_COLORS[si%ENT_COLORS.length];
              if(s.props.children){const cells=React.Children.toArray(s.props.children).filter(c=>c.type===Cell);if(cells[i])fill=cells[i].props.fill;}
              return<g key={`${si}-${i}`}><rect x={x} y={y} width={w} height={h} rx={3} fill={fill} opacity={hov!==null&&hov!==i?0.5:1}/>{React.Children.toArray(s.props.children).find(c=>c.type===LabelList)&&<text x={x+w+8} y={y+h/2+3} fill="#64748b" fontSize={10} fontWeight="700" textAnchor="start">{fmt(v)}</text>}</g>;
            });
          })
        )}
      </svg>
      {leg&&<div className="flex flex-wrap justify-center gap-4 mt-3">{series.map((s,i)=><div key={i} className="flex items-center gap-1.5"><div style={{width:'10px',height:'10px',background:s.fill||s.stroke||ENT_COLORS[i%ENT_COLORS.length],borderRadius:'2px'}}/><span style={{fontSize:'11px',fontWeight:'600',color:'#64748b'}}>{s.name}</span></div>)}</div>}
      {tip&&hov!==null&&data[hov]&&(
        <div style={{position:'absolute',left:mpos.x+16,top:mpos.y-20,pointerEvents:'none',zIndex:100}}>
          {tip.props.content?React.createElement(tip.props.content,{active:true,payload:getTip(hov),label:data[hov][xKey]}):(
            <div style={{background:'#0f172a',border:'1px solid #1e293b',borderRadius:'10px',padding:'10px 14px',boxShadow:'0 20px 25px -5px rgba(0,0,0,0.4)'}}>
              <p style={{color:'#94a3b8',fontSize:'10px',fontWeight:'700',textTransform:'uppercase',letterSpacing:'.05em',marginBottom:'6px'}}>{data[hov][xKey]}</p>
              {getTip(hov).map((p,i)=><p key={i} style={{color:p.color,fontSize:'12px',fontWeight:'700',display:'flex',justifyContent:'space-between',gap:'12px'}}><span style={{color:'#94a3b8'}}>{p.name}</span><span>{fmt(p.value)}</span></p>)}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

export function PieChart({children,containerWidth=300,containerHeight=300}){
  const [hov,setHov]=useState(null);const[mpos,setMpos]=useState({x:0,y:0});
  const ch=React.Children.toArray(children);
  const pie=ch.find(c=>c.type===Pie);const leg=ch.find(c=>c.type===Legend);
  if(!pie)return null;
  const data=pie.props.data||[];const dk=pie.props.dataKey||'value';
  const cx=containerWidth/2;const cy=containerHeight/2;
  const oR=pie.props.outerRadius||90;const iR=pie.props.innerRadius||0;
  const total=data.reduce((a,c)=>a+(parseFloat(c[dk])||0),0);
  function path(cx,cy,iR,oR,sA,eA){
    const r=Math.PI/180;
    const x1=cx+oR*Math.cos(-sA*r),y1=cy+oR*Math.sin(-sA*r);
    const x2=cx+oR*Math.cos(-eA*r),y2=cy+oR*Math.sin(-eA*r);
    const x3=cx+iR*Math.cos(-eA*r),y3=cy+iR*Math.sin(-eA*r);
    const x4=cx+iR*Math.cos(-sA*r),y4=cy+iR*Math.sin(-sA*r);
    return`M ${x1} ${y1} A ${oR} ${oR} 0 ${Math.abs(eA-sA)>180?1:0} 1 ${x2} ${y2} L ${x3} ${y3} A ${iR} ${iR} 0 ${Math.abs(eA-sA)>180?1:0} 0 ${x4} ${y4} Z`;
  }
  let cum=pie.props.startAngle||0;
  const slices=data.map((item,i)=>{
    const v=parseFloat(item[dk])||0;const pct=total>0?v/total:0;const span=pct*360;
    const sA=cum;const eA=cum-span;cum=eA;
    const mid=sA-span/2;const rad=Math.PI/180;const lR=iR+(oR-iR)*.6;
    let fill=ENT_COLORS[i%ENT_COLORS.length];
    if(pie.props.children){const cells=React.Children.toArray(pie.props.children).filter(c=>c.type===Cell);if(cells[i])fill=cells[i].props.fill;}
    return{name:item.name,value:v,pct,sA,eA,lX:cx+lR*Math.cos(-mid*rad),lY:cy+lR*Math.sin(-mid*rad),fill};
  });
  return(
    <div style={{position:'relative',width:'100%',height:'100%'}} onMouseMove={e=>{const r=e.currentTarget.getBoundingClientRect();setMpos({x:e.clientX-r.left,y:e.clientY-r.top});}} onMouseLeave={()=>setHov(null)}>
      <svg width={containerWidth} height={containerHeight} className="overflow-visible">
        {slices.map((s,i)=>(
          <g key={i} onMouseEnter={()=>setHov(i)} onMouseLeave={()=>setHov(null)} style={{transform:hov===i?'scale(1.04)':'none',transformOrigin:`${cx}px ${cy}px`,transition:'transform 0.2s'}}>
            <path d={path(cx,cy,iR,oR,s.sA,s.eA)} fill={s.fill} stroke="#fff" strokeWidth={2} opacity={hov!==null&&hov!==i?0.7:1}/>
            {s.pct>0.06&&iR>40&&<text x={s.lX} y={s.lY} fill="#fff" fontSize={10} fontWeight="800" textAnchor="middle">{(s.pct*100).toFixed(0)}%</text>}
          </g>
        ))}
      </svg>
      {leg&&<div className="flex flex-wrap justify-center gap-x-4 gap-y-1.5 mt-3">{slices.map((s,i)=><div key={i} className="flex items-center gap-1.5"><div style={{width:'8px',height:'8px',background:s.fill,borderRadius:'50%'}}/><span style={{fontSize:'10px',fontWeight:'600',color:'#64748b'}}>{s.name}</span></div>)}</div>}
      {hov!==null&&slices[hov]&&(
        <div style={{position:'absolute',left:mpos.x+16,top:mpos.y-20,pointerEvents:'none',zIndex:100}}>
          <div style={{background:'#0f172a',border:'1px solid #1e293b',borderRadius:'10px',padding:'10px 14px'}}>
            <p style={{color:slices[hov].fill,fontSize:'12px',fontWeight:'700'}}>{slices[hov].name}: {slices[hov].value} <span style={{color:'#64748b'}}>({(slices[hov].pct*100).toFixed(1)}%)</span></p>
          </div>
        </div>
      )}
    </div>
  );
}
