    indigo:{bg:'bg-indigo-50',iconBg:'bg-indigo-100',icon:'text-indigo-600',val:'text-indigo-700',border:'border-indigo-100'},
    emerald:{bg:'bg-emerald-50',iconBg:'bg-emerald-100',icon:'text-emerald-600',val:'text-emerald-700',border:'border-emerald-100'},
    amber:{bg:'bg-amber-50',iconBg:'bg-amber-100',icon:'text-amber-600',val:'text-amber-700',border:'border-amber-100'},
    red:{bg:'bg-red-50',iconBg:'bg-red-100',icon:'text-red-600',val:'text-red-700',border:'border-red-100'},
    slate:{bg:'bg-slate-50',iconBg:'bg-slate-100',icon:'text-slate-600',val:'text-slate-700',border:'border-slate-200'},
