  // IA
  const [chatMsg,setChatMsg]=useState([{role:'assistant',content:'Sou o Analista IA do Kalenborn SGQ. Posso gerar relatórios executivos, cruzar dados de remessas e estoque, e criar visualizações corporativas. Como posso ajudar?'}]);
  const [chatIn,setChatIn]=useState('');
  const [chatLoad,setChatLoad]=useState(false);
  const [miniOpen,setMiniOpen]=useState(false);
  const [miniMsg,setMiniMsg]=useState([{role:'assistant',content:'Copiloto ativo. Pergunte sobre saldos, remessas ou projetos em aberto.'}]);
  const [miniIn,setMiniIn]=useState('');
  const [miniLoad,setMiniLoad]=useState(false);
  const [chatEqOpen,setChatEqOpen]=useState(false);
  const [chatEqIn,setChatEqIn]=useState('');
  const [chatEqDest,setChatEqDest]=useState('Geral');
  const [chatEqUnread,setChatEqUnread]=useState(false);
  const chatEndRef=useRef(null);
  const [relApres,setRelApres]=useState(null);

  // Usuarios
  const [novoUser,setNovoUser]=useState({nome:'',email:'',senha:'',perfil:'PCP'});
  const [editUser,setEditUser]=useState(false);
  const [expandida,setExpandida]=useState(null);

  const isAdmin=usuarioLogado?.perfil==='ADMIN';
  const isPCP=usuarioLogado?.perfil==='PCP'||isAdmin;
  const isExp=usuarioLogado?.perfil==='EXPEDICAO'||isAdmin;

  const s=v=>(v===null||v===undefined)?'':String(v);
  const fmtD=(v,u='')=>{if(v===undefined||v===null||isNaN(v)||v==='')return'—';const n=parseFloat(v);const st=Number.isInteger(n)?n.toString():n.toFixed(2).replace('.',',');return u?`${st} ${u}`:st;};
  const fmtDt=v=>v?new Date(v).toLocaleDateString('pt-BR'):'—';
  const parseN=v=>{if(typeof v==='number')return v;if(!v)return 0;let st=s(v?.result||v).trim();if(st.includes('.')&&st.includes(',')){if(st.indexOf('.')<st.indexOf(','))st=st.replace(/\./g,'').replace(',','.');else st=st.replace(/,/g,'');}else st=st.replace(',','.');return parseFloat(st)||0;};
  const normKey=k=>s(k).toUpperCase().trim().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/\s+/g,'_').replace(/[.-]/g,'');

  const addToast=useCallback((msg,type='success')=>{const id=Date.now();setToasts(p=>[...p,{id,message:msg,type}]);},[]);
  const removeToast=useCallback(id=>setToasts(p=>p.filter(t=>t.id!==id)),[]);

  useEffect(()=>{
    const scripts=[
      {id:'xlsx-lib',src:'https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js'},
      {id:'exceljs-lib',src:'https://cdnjs.cloudflare.com/ajax/libs/exceljs/4.3.0/exceljs.min.js'},
      {id:'supabase-lib',src:'https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2'}
    ];
    scripts.forEach(sc=>{if(!document.getElementById(sc.id)){const el=document.createElement('script');el.id=sc.id;el.src=sc.src;el.async=true;document.body.appendChild(el);}});
    const chk=setInterval(()=>{if(window.supabase){try{const cl=window.supabase.createClient(SUPABASE_URL,SUPABASE_KEY);setSupa(cl);clearInterval(chk);}catch(e){}}},500);
    return()=>clearInterval(chk);
  },[]);

  const fetchAll=useCallback(async()=>{
    if(!supabase)return;
    try{
      const[pR,eR,rR,uR,cR,chR,rlR]=await Promise.all([
        supabase.from('produtos').select('*'),
        supabase.from('estoque_mp').select('*'),
        supabase.from('remessas').select('*').order('data_criacao',{ascending:false}),
        supabase.from('perfis_usuarios').select('*'),
        supabase.from('configuracoes').select('*').in('chave',['modelo_sgq','openai_api_key','planner_flow_url']),
        supabase.from('chat_interno').select('*').order('data_envio',{ascending:true}),
        supabase.from('relatorios_ia').select('*').order('data_criacao',{ascending:false})
      ]);
      if(pR.data){const m={};pR.data.forEach(p=>{if(p.codigo_pa)m[p.codigo_pa]=p;});setProdutosDb(m);}
      if(eR.data){const m={};eR.data.forEach(e=>{if(e.codigo_mp)m[e.codigo_mp]=e;});setEstoqueDb(m);}
      if(rR.data)setRemessasDb(rR.data);
      if(uR.data)setUsuariosDb(uR.data);
      if(cR.data){
        const modelo=cR.data.find(c=>c.chave==='modelo_sgq');
        if(modelo?.valor_json){const b64=modelo.valor_json.data;setNomeTemplate(modelo.valor_json.nome);const bs=window.atob(b64);const bytes=new Uint8Array(bs.length);for(let i=0;i<bs.length;i++)bytes[i]=bs.charCodeAt(i);setTemplateBuf(bytes.buffer);}
        const ak=cR.data.find(c=>c.chave==='openai_api_key');if(ak?.valor_json)setOpenAIKey(ak.valor_json.key);
        const pk=cR.data.find(c=>c.chave==='planner_flow_url');if(pk?.valor_json)setPlannerUrl(pk.valor_json.url);
      }
      if(chR.data){if(chatInternoDb.length>0&&chR.data.length>chatInternoDb.length&&!chatEqOpen)setChatEqUnread(true);setChatInternoDb(chR.data);}
      if(rlR.data)setRelatoriosIaDb(rlR.data);
      setDbOnline(true);
    }catch(e){setDbOnline(false);}
  },[supabase,chatEqOpen]);

  useEffect(()=>{if(supabase){fetchAll();const iv=setInterval(fetchAll,10000);return()=>clearInterval(iv);}},[supabase]);
  useEffect(()=>{if(chatEndRef.current)chatEndRef.current.scrollIntoView({behavior:'smooth'});},[chatInternoDb,chatEqOpen]);

  const handleSort=(st,setSt,k)=>setSt(p=>({key:k,dir:p.key===k&&p.dir==='asc'?'desc':'asc'}));

  const handleLogin=async e=>{
    e.preventDefault();setErroLogin('');setLoginLoading(true);
    if(!supabase){setErroLogin('Aguardando conexão...');setLoginLoading(false);return;}
    try{
      const{data}=await supabase.from('perfis_usuarios').select('*').eq('email',emailLogin.toLowerCase().trim()).eq('senha',senhaLogin).single();
      if(data){setUsuarioLogado(data);setAba(data.perfil==='EXPEDICAO'?'EXPEDICAO':'DASHBOARD');}
      else setErroLogin('Credenciais inválidas.');
    }catch(e){setErroLogin('Falha de autenticação.');}finally{setLoginLoading(false);}
  };

  const salvarUser=async e=>{
    e.preventDefault();setIsLoading(true);
    try{const{error}=await supabase.from('perfis_usuarios').upsert([novoUser],{onConflict:'email'});if(error)throw error;addToast('Usuário salvo!');setNovoUser({nome:'',email:'',senha:'',perfil:'PCP'});setEditUser(false);fetchAll();}
    catch(e){addToast('Erro: '+e.message,'error');}finally{setIsLoading(false);}
  };

  const excluirUser=async email=>{
    if(email===usuarioLogado?.email)return addToast('Não pode remover seu próprio acesso.','error');
    if(window.confirm('Remover permanentemente?')){await supabase.from('perfis_usuarios').delete().eq('email',email);addToast('Usuário removido.');fetchAll();}
  };

  const buscarProduto=e=>{
    if(e)e.preventDefault();setModoManual(false);
    const cod=codigoBusca.toUpperCase().trim();const prod=produtosDb[cod];
    if(prod){
      setProdEncontrado(prod);
      const list=(prod.materiais||[]).map(m=>{
        const est=estoqueDb[m.codigoMP]||{saldo_disponivel:0,descricao:'Não catalogado'};
        const qb=Number((m.quantidade*parseN(qtdProd)).toFixed(4));
        return{...m,saldoDisponivel:est.saldo_disponivel,descricao:est.descricao,quantidadeTotal:qb,quantidadeOriginal:qb,quantidadeRetornada:0,rateiosExtras:[]};
      });
      setItens(list);setItensOrig(list);
    }else{
      if(window.confirm('Produto não encontrado na BOM. Criar remessa manual?')){setModoManual(true);setProdEncontrado({codigo_pa:cod,descricao:'ITEM MANUAL'});setItens([]);setItensOrig([]);}
    }
  };

  const addItemManual=()=>{
    if(!novoItemM.codigoMP||!novoItemM.descricao||!novoItemM.quantidade)return addToast('Preencha código, descrição e quantidade.','error');
    const est=estoqueDb[novoItemM.codigoMP.toUpperCase()]||{saldo_disponivel:0};
    const qb=parseN(novoItemM.quantidade);
    setItens(p=>[...p,{codigoMP:novoItemM.codigoMP.toUpperCase(),descricao:novoItemM.descricao.toUpperCase(),um:novoItemM.um.toUpperCase(),quantidadeTotal:qb,quantidadeOriginal:qb,quantidadeRetornada:0,rateiosExtras:[],saldoDisponivel:est.saldo_disponivel}]);
    setNovoItemM({codigoMP:'',descricao:'',quantidade:'',um:'UN'});
  };

  const enviarExpedicao=async()=>{
    if(!projeto||!cliente)return addToast('Projeto e Cliente são obrigatórios.','error');
    if(isComp&&!opPaiId)return addToast('Selecione a OP original.','error');
    const semSaldo=itens.filter(it=>it.saldoDisponivel<it.quantidadeTotal);
    if(semSaldo.length>0)return addToast(`Saldo insuficiente: ${semSaldo.map(s=>s.codigoMP).join(', ')}`,'error');
    const servFinal=servico==='Outros'?(outrosTexto||'Outros'):servico;
    const removidos=itensOrig.filter(o=>!itens.find(it=>it.codigoMP===o.codigoMP)).map(r=>({codigoMP:s(r.codigoMP),descricao:s(r.descricao),quantidade:Number(r.quantidadeTotal),um:s(r.um)}));
    // Registrar TODOS os itens com quantidade alterada + justificativa
    const alterados=itens.filter(it=>it.quantidadeTotal!==it.quantidadeOriginal);
    let notaFinal=obsExp;
    if(alterados.length>0){
      const nt=`[Ajuste PCP: ${alterados.map(a=>{const df=a.quantidadeTotal-a.quantidadeOriginal;const just=a.justificativa?` — "${a.justificativa}"`:' — sem justificativa';return`${a.codigoMP}: BOM=${fmtD(a.quantidadeOriginal)}→Enviado=${fmtD(a.quantidadeTotal)} ${a.um}${just}`;}).join(' | ')}]`;
      notaFinal=notaFinal?`${notaFinal} — ${nt}`:nt;
    }
    // Validar: itens com alteração devem ter justificativa
    const semJustificativa=alterados.filter(it=>!it.justificativa?.trim());
    if(semJustificativa.length>0)return addToast(`Justifique a alteração nos itens: ${semJustificativa.map(x=>x.codigoMP).join(', ')}`,'error');
    setIsLoading(true);
    try{
      for(const it of itens){const{data:cur}=await supabase.from('estoque_mp').select('saldo_disponivel').eq('codigo_mp',it.codigoMP).single();await supabase.from('estoque_mp').update({saldo_disponivel:Number(((cur?.saldo_disponivel||0)-it.quantidadeTotal).toFixed(4))}).eq('codigo_mp',it.codigoMP);}
      const nr={id:`REM-${Date.now()}`,produto_acabado:s(prodEncontrado.codigo_pa),descricao_produto:s(prodEncontrado.descricao),quantidade_op:parseN(qtdProd),projeto:s(projeto).toUpperCase(),cliente:s(cliente).toUpperCase(),observacao:s(servFinal),obs_expedicao:s(notaFinal),itens,itens_removidos:removidos,status:'PENDENTE_EXPEDICAO',criado_por:s(usuarioLogado?.nome||'PCP'),pecas_recebidas:0,remessa_pai_id:isComp?s(opPaiId):null,data_envio_prevista:dataEnvioPrevista||null,data_retorno_desejada:dataRetornoDesejada||null};
      const{error}=await supabase.from('remessas').insert([nr]);if(error)throw error;
      addToast('Remessa enviada para Expedição!');
      setIsLoading(false);setProdEncontrado(null);setOutrosTexto('');setObsExp('');setCliente('');setIsComp(false);setOpPaiId('');setModoManual(false);setAba('HISTORICO_PCP');fetchAll();
    }catch(e){addToast('Erro: '+e.message,'error');setIsLoading(false);}
  };

  const concluirExp=async()=>{
    if(!templateBuf)return addToast('Modelo SGQ não carregado.','error');
    if(!formExp.transporte||!formExp.destinatario)return addToast('Preencha Transporte e Destinatário.','error');
    setIsLoading(true);
    try{
      const{error}=await supabase.from('remessas').update({status:'ENVIADO',data_envio:new Date().toISOString(),enviado_por:s(usuarioLogado?.nome),expedicao:formExp}).eq('id',remSel.id);if(error)throw error;
      const wb=new window.ExcelJS.Workbook();await wb.xlsx.load(templateBuf);const ws=wb.worksheets[0];
      ws.getCell('B4').value=s(remSel.projeto);ws.getCell('C4').value=s(remSel.cliente);
      ws.getCell('B6').value=s(formExp.transporte);ws.getCell('C6').value=s(formExp.transportadora);
      ws.getCell('B8').value=Number(formExp.quantidade);ws.getCell('C8').value=s(formExp.pesoTotal);
      ws.getCell('E8').value=`${s(remSel.projeto)} — ${s(formExp.destinatario)}`;ws.getCell('G8').value=s(formExp.dataSaida);
      (remSel.itens||[]).forEach((it,i)=>{const r=12+i;ws.getCell(`C${r}`).value=s(it.codigoMP);ws.getCell(`E${r}`).value=s(it.descricao);ws.getCell(`F${r}`).value=Number(it.quantidadeTotal);ws.getCell(`G${r}`).value=s(it.um);ws.getCell(`H${r}`).value=s(remSel.observacao);});
      const buf=await wb.xlsx.writeBuffer();const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([buf]));a.download=`SGQ_${s(remSel.projeto)}.xlsx`;a.click();
      addToast('Expedição concluída!');setRemSel(null);setIsLoading(false);fetchAll();
    }catch(e){addToast('Falha ao gerar planilha.','error');setIsLoading(false);}
  };

  const processarRetorno=async()=>{
    const pd=parseN(qtdRet);const rem=remParaRet;if(!rem)return;
    const jaRec=Number(rem.pecas_recebidas||0);const saldo=Number(rem.quantidade_op)-jaRec;
    if(pd<=0||pd>saldo)return addToast('Quantidade inválida.','error');
    setIsLoading(true);
    try{
      const prop=pd/Number(rem.quantidade_op);const novosItens=[...(rem.itens||[])];
      for(let i=0;i<novosItens.length;i++){
        const qm=Number((novosItens[i].quantidadeTotal*prop).toFixed(4));
        novosItens[i].quantidadeRetornada=Number(((novosItens[i].quantidadeRetornada||0)+qm).toFixed(4));
        const{data:cur}=await supabase.from('estoque_mp').select('saldo_disponivel').eq('codigo_mp',novosItens[i].codigoMP).single();
        await supabase.from('estoque_mp').update({saldo_disponivel:Number(((cur?.saldo_disponivel||0)+qm).toFixed(4))}).eq('codigo_mp',novosItens[i].codigoMP);
      }
      const total=jaRec+pd;const novoSt=total>=Number(rem.quantidade_op)?'RETORNADO':'RETORNO_PARCIAL';
      const{error}=await supabase.from('remessas').update({itens:novosItens,status:novoSt,pecas_recebidas:total,data_retorno:new Date().toISOString(),recebido_por:s(usuarioLogado?.nome)}).eq('id',rem.id);
      if(error)throw error;
      addToast('Estoque atualizado com o retorno!');setRemParaRet(null);setQtdRet('');fetchAll();
    }catch(e){addToast('Erro no retorno.','error');}finally{setIsLoading(false);}
  };

