      if(semSaldo.length>0)return addToast('Saldo insuficiente: '+semSaldo.map(x=>x.codigoMP).join(', '),'error');
      const orig=remEditando.itens||[];
      // Reverter estoque dos itens originais
      for(const it of orig){const{data:cur}=await supabase.from('estoque_mp').select('saldo_disponivel').eq('codigo_mp',it.codigoMP).single();await supabase.from('estoque_mp').update({saldo_disponivel:Number(((cur?.saldo_disponivel||0)+it.quantidadeTotal).toFixed(4))}).eq('codigo_mp',it.codigoMP);}
      // Baixar estoque dos novos itens
      for(const it of editItens){const{data:cur}=await supabase.from('estoque_mp').select('saldo_disponivel').eq('codigo_mp',it.codigoMP).single();await supabase.from('estoque_mp').update({saldo_disponivel:Number(((cur?.saldo_disponivel||0)-it.quantidadeTotal).toFixed(4))}).eq('codigo_mp',it.codigoMP);}
      const removidos=orig.filter(o=>!editItens.find(it=>it.codigoMP===o.codigoMP)).map(r=>({codigoMP:s(r.codigoMP),descricao:s(r.descricao),quantidade:Number(r.quantidadeTotal),um:s(r.um)}));
